('937ea54d-9fb7-4e83-b623-5c73926cac03', 'CRE 01/2022', 'CIS AMOSC', '<div><span style="font-size: 0.875rem; color: rgb(12, 54, 14);">O presente edital tem por objeto o credenciamento de pessoas jurídicas prestadoras com atuação na área da saúde, nas especialidades descritas no Anexo I do Edital, conforme demandas existentes nos municípios consorciados, para desempenhar a prestação de serviços/funções junto ao Centro De Referência De Especialidades Medicas Regional - CREMER - CISAMOSC, com atendimento exclusivo aos usuários do sistema único de saúde – SUS, com vistas à complementação dos serviços de saúde ofertados pela rede de saúde pública, nos termos especificados neste edital e nas condições estabelecidas em seus anexos.</span></div>', NULL, NULL, NULL, 'descarte_edital', '11d70a5b-11c2-4651-8521-de3c8a00a2b4', NULL, '2026-02-20T12:14:53.871Z', '2026-02-25T18:52:57.262Z', NULL, 'CHAPECÓ/SC', 'Credenciamento', NULL, '{}', 'Manual', NULL, 'CRE 01/2022-RETIF_ CIS- AMOS/CHAPECÓ-SC', '{}', false, false, false, false, false, false, '{}', NULL, 'AGES', 'alta', false, 'PROC. AUXILIAR', NULL, NULL),
('1e2de894-65f7-4454-b7b2-1ed2b1fbe16e', '002/26', 'JOAÇABA/SC', '&nbsp;Contratação de pessoa jurídica especializada para prestação de serviços médicos em Endoscopia Digestiva, Colonoscopia (diagnóstica e terapêutica) e CPRE, compreendendo:  Atendimento eletivo com meta mínima mensal;  Cobertura de urgência em regime de sobreaviso;  Responsabilidade Técnica do serviço. A contratação refere-se exclusivamente a honorários médicos, sendo os demais custos (estrutura, anestesia, equipe de apoio e insumos) de responsabilidade do HUST&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<div></div><div data-highlight-box="true" style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b><font color="#dc2626">Preço máximo global estimado (TEMOS QUE ENTRAR EM TUDO)</font></b></div><div></div></div><div><div data-highlight-box="true" style="background-color: rgb(249, 250, 251); border: 2px solid rgb(107, 114, 128); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b style="color: rgb(220, 38, 38);">ENVELOPES DEVEM SER ENTREGUES ATÉ DIA 13/04/26 &gt;&gt;&gt;&gt;&gt;&gt;&gt;</b><b style=""><font color="#9333ea"> ABERTURA DOS ENVELOPES DIA 15/04/2026 ÁS 14H</font></b><br><br><b style="color: rgb(220, 38, 38);">O valor proposto DEVE SER IGUAL OU INFERIOR</b><br><br><font color="#dc2626" style="font-weight: bold;">a) A Licitante Vencedora será aquela que realizar a menor oferta de preço</font><font color="#000000" style=""><b>, </b>nos termos estabelecidos neste Edital, respeitado o valor máximo estimado, o qual passará para a fase da habilitação</font><br><br><b style="color: rgb(220, 38, 38);">O prazo de execução é IMEDIATO após a assinatura do contrato.</b></div><div></div></div><div><div data-highlight-box="true" style="background-color: rgb(240, 253, 244); border: 2px solid rgb(34, 197, 94); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><div><b><u><font color="#dc2626"><br></font></u></b></div><div><b><u><font color="#dc2626">1.2.4 Em relação as horas coletivas mensais para Endoscopistas / Colonoscopistas temos:<br></font></u></b><br></div><div>a) <b>Endoscopista / colonoscopista:</b> 1 médico trabalhando 12h por dia, (07h as 19h), nos 7 dias da semana.<br><br></div><div>b)<b> Endoscopista sobreaviso: </b>1 médico trabalhando 12h por dia (19h as 07h), nos 7 dias da semana.&nbsp;<br></div></div><div data-highlight-box="true" style="background-color: rgb(255, 251, 235); border: 2px solid rgb(245, 158, 11); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><p><b><font color="#dc2626">A ESTRUTURA DO SERVIÇO</font></b>:&nbsp;<span style="font-size: 0.875rem;"><font color="#0c360e">A empresa deve </font><b style=""><u style=""><font color="#dc2626">preferencialmente</font></u></b><font color="#0c360e"> possuir certificação de qualidade expedidos por programas de certificação e acreditação.</font></span></p><div></div></div><div data-highlight-box="true" style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><p><font color="#dc2626"><b>Os procedimentos que fazem parte da endoscopia digestiva e que deverão ser prestados pela Contratada são:</b></font></p><p><span style="font-size: 0.875rem; color: rgb(12, 54, 14);">Gastrostomia Via Endoscópica;&nbsp;</span></p><p>Ligadura Elástica De Varizes Esofagiana</p><p>Hemostasia;&nbsp;</p><p>Esclerose Com Cianoacrilato;&nbsp;</p><p>Escleroterapia;&nbsp;</p><p>Endoscopia Digestiva;&nbsp;</p><p>Retirada De Corpo Estranho;&nbsp;</p><p>Polipectomia;&nbsp;</p><p>Troca Sonda Gastrostomia;&nbsp;</p><p>Passagem Sonda;</p><p>&nbsp;Dilatação De Esofago;</p><p>Mucosectomia; Biopsias.</p></div><p></p><div data-highlight-box="true" style="background-color: rgb(250, 245, 255); border: 2px solid rgb(168, 85, 247); border-radius: 6px; padding: 12px; margin: 8px 0px; display: block; min-width: 100px;"><p><font color="#dc2626"><b>Os procedimentos que fazem parte da colonoscopia e que deverão ser prestados pela Contratada são:&nbsp;</b></font></p><p>Hemostasia;&nbsp;</p><p>Colonoscopia;&nbsp;</p><p>Retirada De Corpo Estranho;&nbsp;</p><p>Retosigmoidoscopia rígida e Flexivel + Anuscopia – Colono;</p><p>Polipectomia; Mucosectomia; Biopsias</p></div><p><br></p><p></p><p></p><div> &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</div></div></div>', '109205.00', NULL, NULL, 'descarte_edital', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', NULL, '2026-03-06T12:33:47.624Z', '2026-03-06T15:57:21.904Z', NULL, 'JOAÇABA/SC', 'Concorrência', '2026-04-15T12:32:00.000Z', '{}', 'Manual', NULL, 'CONCORRENCIA 002/26 JOAÇABA/SC', '{}', false, false, false, false, false, false, '{}', NULL, 'GSS', 'alta', false, 'MODALIDADE', NULL, NULL),
